/**
 * OwlFly physics tuning goals:
 * - flap should feel immediate and readable
 * - upward motion should have a short, satisfying lift
 * - falling should feel dangerous but not uncontrollable
 * - rotation should communicate state clearly
 */

const FLAP_GRAVITY_RECOVERY_BOOST = 1.12;
const FAST_FALL_EXTRA = 1.08;
const UPWARD_VELOCITY_SOFT_CAP = 1.18;function applyGravity(vy, dt, gravityScale = 1, maxFallScale = 1) {
  const s = Number.isFinite(gravityScale) ? gravityScale : 1;
  const fallCapScale = Number.isFinite(maxFallScale) ? maxFallScale : 1;

  let nextVy = vy;

  if (nextVy < 0) {
    nextVy += WORLD.GRAVITY * s * FLAP_GRAVITY_RECOVERY_BOOST * dt;
  } else {
    nextVy += WORLD.GRAVITY * s * FAST_FALL_EXTRA * dt;
  }

  const maxFall = Math.max(120, WORLD.MAX_FALL_SPEED * fallCapScale);
  if (nextVy > maxFall) nextVy = maxFall;

  return nextVy;
}function jumpImpulse(impulseScale = 1) {
  const s = Number.isFinite(impulseScale) ? impulseScale : 1;
  const raw = -WORLD.JUMP_IMPULSE * s;
  const riseCap = -WORLD.JUMP_IMPULSE * s * UPWARD_VELOCITY_SOFT_CAP;
  return Math.max(raw, riseCap);
}function rotationForVelocity(vy, upScale = 1, downScale = 1) {
  const safeUpScale = Number.isFinite(upScale) ? upScale : 1;
  const safeDownScale = Number.isFinite(downScale) ? downScale : 1;

  const riseRange = Math.max(1, WORLD.JUMP_IMPULSE * 1.25);
  const fallRange = Math.max(1, WORLD.MAX_FALL_SPEED);

  if (vy < 0) {
    const riseT = Math.min(1, Math.abs(vy) / riseRange);
    return WORLD.ROT_UP * safeUpScale * riseT;
  }

  const fallT = Math.min(1, vy / fallRange);
  return WORLD.ROT_DOWN * safeDownScale * Math.pow(fallT, 0.82);
}


// ===== FILE: src/engine/collision.js =====

function aabbIntersect(a, b) {
  return (
    a.x < b.x + b.w &&
    a.x + a.w > b.x &&
    a.y < b.y + b.h &&
    a.y + a.h > b.y
  );
}function circleAabbIntersect(cx, cy, r, rect) {
  const closestX = clamp(cx, rect.x, rect.x + rect.w);
  const closestY = clamp(cy, rect.y, rect.y + rect.h);
  const dx = cx - closestX;
  const dy = cy - closestY;
  return dx * dx + dy * dy <= r * r;
}function forgivingCircleAabbIntersect(cx, cy, r, rect, forgiveness = 0.92) {
  const rr = Math.max(1, r * forgiveness);
  return circleAabbIntersect(cx, cy, rr, rect);
}function resolveHitSide(cx, cy, rect) {
  const left = Math.abs(cx - rect.x);
  const right = Math.abs(cx - (rect.x + rect.w));
  const top = Math.abs(cy - rect.y);
  const bottom = Math.abs(cy - (rect.y + rect.h));

  const min = Math.min(left, right, top, bottom);

  if (min === left) return "left";
  if (min === right) return "right";
  if (min === top) return "top";
  return "bottom";
}

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

// ===== FILE: src/engine/difficulty.js =====

class Difficulty {
  constructor() {
    this.reset();
  }

  reset() {
    this.time = 0;
    this.speed = OBSTACLE.BASE_SPEED;
    this.gap = Math.round((OBSTACLE.MIN_GAP + OBSTACLE.MAX_GAP) / 2);
    this.spawnInterval = SPAWN.BASE_INTERVAL;
  }

  update(dt) {
    this.time += dt;

    this.speed = Math.min(
      OBSTACLE.SPEED_MAX,
      OBSTACLE.BASE_SPEED + DIFFICULTY.SPEED_RAMP_PER_SEC * this.time
    );

    this.gap = Math.max(
      OBSTACLE.MIN_GAP,
      Math.round(
        ((OBSTACLE.MIN_GAP + OBSTACLE.MAX_GAP) / 2) -
          DIFFICULTY.GAP_SHRINK_PER_SEC * this.time
      )
    );

    this.spawnInterval = Math.max(
      SPAWN.MIN_INTERVAL,
      SPAWN.BASE_INTERVAL - DIFFICULTY.INTERVAL_SHRINK_PER_SEC * this.time
    );
  }
}

// ===== FILE: src/engine/input.js =====

class Input {
  constructor(canvas) {
    this.canvas = canvas;
    this._jump = false;
    this._pause = false;

    this._onKeyDown = (e) => {
      if (e.code === "Space") { e.preventDefault(); this._jump = true; }
      if (e.code === "Enter") this._jump = true;
      if (e.code === "Escape") this._pause = true;
    };

    this._onPointerDown = (e) => {
      e.preventDefault();
      this._jump = true;
    };

    window.addEventListener("keydown", this._onKeyDown, { passive: false });
    canvas.addEventListener("pointerdown", this._onPointerDown, { passive: false });
  }

  consumeJump() {
    const v = this._jump;
    this._jump = false;
    return v;
  }

  consumePause() {
    const v = this._pause;
    this._pause = false;
    return v;
  }

  dispose() {
    window.removeEventListener("keydown", this._onKeyDown);
    this.canvas.removeEventListener("pointerdown", this._onPointerDown);
  }
}


